You are implementing Task 21: Stripe Integration (Merchant Subscriptions) for a loyalty card app.

**Working directory:** C:\Users\User\loyalty-app

**What to do:**

### 1. Install Stripe in the dashboard app

```bash
cd apps/dashboard && pnpm add stripe
```

### 2. Create `apps/dashboard/src/app/api/stripe/checkout/route.ts`

```typescript
import { NextResponse } from 'next/server';
import Stripe from 'stripe';
import { createClient } from '@/lib/supabase/server';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);

const PRICE_IDS: Record<string, string> = {
  pro: process.env.STRIPE_PRO_PRICE_ID!,
  business: process.env.STRIPE_BUSINESS_PRICE_ID!,
};

export async function POST(req: Request) {
  const { plan } = await req.json();
  if (!plan || !PRICE_IDS[plan]) {
    return NextResponse.json({ error: 'Invalid plan' }, { status: 400 });
  }

  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

  const { data: merchant } = await supabase.from('merchants').select('*').eq('user_id', user.id).single();
  if (!merchant) return NextResponse.json({ error: 'Merchant not found' }, { status: 404 });

  let customerId = merchant.stripe_customer_id;
  if (!customerId) {
    const customer = await stripe.customers.create({ email: user.email, metadata: { merchant_id: merchant.id } });
    customerId = customer.id;
    await supabase.from('merchants').update({ stripe_customer_id: customerId }).eq('id', merchant.id);
  }

  const session = await stripe.checkout.sessions.create({
    customer: customerId,
    mode: 'subscription',
    line_items: [{ price: PRICE_IDS[plan], quantity: 1 }],
    success_url: `${process.env.NEXT_PUBLIC_APP_URL}/subscription?success=true`,
    cancel_url: `${process.env.NEXT_PUBLIC_APP_URL}/subscription?cancelled=true`,
  });

  return NextResponse.json({ url: session.url });
}
```

### 3. Create `apps/dashboard/src/app/api/stripe/webhook/route.ts`

```typescript
import { NextResponse } from 'next/server';
import Stripe from 'stripe';
import { createClient as createSupabaseAdmin } from '@supabase/supabase-js';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);

// Use admin client (service role) for webhook processing
function getAdminClient() {
  return createSupabaseAdmin(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!
  );
}

export async function POST(req: Request) {
  const body = await req.text();
  const sig = req.headers.get('stripe-signature');
  if (!sig) return NextResponse.json({ error: 'Missing signature' }, { status: 400 });

  let event: Stripe.Event;
  try {
    event = stripe.webhooks.constructEvent(body, sig, process.env.STRIPE_WEBHOOK_SECRET!);
  } catch {
    return NextResponse.json({ error: 'Invalid signature' }, { status: 400 });
  }

  const supabase = getAdminClient();

  switch (event.type) {
    case 'customer.subscription.created':
    case 'customer.subscription.updated': {
      const sub = event.data.object as Stripe.Subscription;
      const priceId = sub.items.data[0]?.price?.id;
      let plan = 'free';
      if (priceId === process.env.STRIPE_PRO_PRICE_ID) plan = 'pro';
      else if (priceId === process.env.STRIPE_BUSINESS_PRICE_ID) plan = 'business';

      await supabase.from('merchants')
        .update({ plan, subscription_status: sub.status })
        .eq('stripe_customer_id', sub.customer as string);
      break;
    }
    case 'customer.subscription.deleted': {
      const sub = event.data.object as Stripe.Subscription;
      await supabase.from('merchants')
        .update({ plan: 'free', subscription_status: 'cancelled' })
        .eq('stripe_customer_id', sub.customer as string);
      break;
    }
  }

  return NextResponse.json({ received: true });
}
```

### 4. Create `apps/dashboard/src/app/(dashboard)/subscription/page.tsx`

A **client component** ('use client') with:
- 3 pricing cards: Free (0 EUR), Pro (29 EUR/month), Business (79 EUR/month)
- Each card lists included features from the design:
  - Free: 1 program, 100 clients, 2 push/month, basic analytics
  - Pro: 3 programs, unlimited clients, unlimited push, analytics, segments
  - Business: Unlimited programs, advanced campaigns, A/B test, multi-location, API, priority support
- Current plan highlighted, upgrade buttons call `/api/stripe/checkout` with the plan and redirect to Stripe checkout
- Show success/cancelled messages from URL params using `useSearchParams()`

### 5. Create `supabase/migrations/004_plan_limits.sql`

```sql
create or replace function public.check_program_limit()
returns trigger as $$
declare merchant_plan text; program_count int;
begin
  select plan into merchant_plan from merchants where id = new.merchant_id;
  select count(*) into program_count from loyalty_programs where merchant_id = new.merchant_id;
  if merchant_plan = 'free' and program_count >= 1 then raise exception 'Free plan: 1 program max'; end if;
  if merchant_plan = 'pro' and program_count >= 3 then raise exception 'Pro plan: 3 programs max'; end if;
  return new;
end;
$$ language plpgsql;

create trigger check_program_limit_trigger
  before insert on public.loyalty_programs
  for each row execute function public.check_program_limit();
```

### 6. Update `.env.example` in apps/dashboard

Add these variables:
```
STRIPE_SECRET_KEY=
STRIPE_WEBHOOK_SECRET=
STRIPE_PRO_PRICE_ID=
STRIPE_BUSINESS_PRICE_ID=
NEXT_PUBLIC_APP_URL=http://localhost:3000
SUPABASE_SERVICE_ROLE_KEY=
```

Important: Read the existing `.env.example` first and add only new variables that aren't already there.

### 7. Commit

```bash
git add .
git commit -m "feat: integrate Stripe subscriptions with plan enforcement"
```

**Context:**
- The dashboard uses Next.js 15 with App Router
- shadcn/ui components are available (Card, Button, etc.)
- Supabase server client is at `@/lib/supabase/server`, browser client at `@/lib/supabase/client`
- The merchants table has `plan`, `subscription_status`, and `stripe_customer_id` columns
- Install `@supabase/supabase-js` as a dependency if needed for the webhook admin client (it may already be installed)
- Do NOT skip the commit step

