'use client';

import { useEffect, useState } from 'react';
import { useSearchParams } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import {
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  CardFooter,
} from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Check } from 'lucide-react';

interface Plan {
  id: string;
  name: string;
  price: string;
  period: string;
  description: string;
  features: string[];
}

const plans: Plan[] = [
  {
    id: 'free',
    name: 'Free',
    price: '0',
    period: '/month',
    description: 'Get started with loyalty programs',
    features: [
      '1 loyalty program',
      'Up to 100 clients',
      '2 push notifications/month',
      'Basic analytics',
    ],
  },
  {
    id: 'pro',
    name: 'Pro',
    price: '29',
    period: '/month',
    description: 'For growing businesses',
    features: [
      '3 loyalty programs',
      'Unlimited clients',
      'Unlimited push notifications',
      'Advanced analytics',
      'Customer segments',
    ],
  },
  {
    id: 'business',
    name: 'Business',
    price: '79',
    period: '/month',
    description: 'For large-scale operations',
    features: [
      'Unlimited programs',
      'Advanced campaigns',
      'A/B testing',
      'Multi-location support',
      'API access',
      'Priority support',
    ],
  },
];

export default function SubscriptionPage() {
  const searchParams = useSearchParams();
  const success = searchParams.get('success');
  const cancelled = searchParams.get('cancelled');

  const [currentPlan, setCurrentPlan] = useState<string>('free');
  const [loading, setLoading] = useState<string | null>(null);

  useEffect(() => {
    async function fetchPlan() {
      const supabase = createClient();
      const {
        data: { user },
      } = await supabase.auth.getUser();
      if (!user) return;

      const { data: merchant } = await supabase
        .from('merchants')
        .select('plan')
        .eq('user_id', user.id)
        .single();

      if (merchant) {
        setCurrentPlan(merchant.plan);
      }
    }
    fetchPlan();
  }, []);

  async function handleUpgrade(plan: string) {
    if (plan === 'free' || plan === currentPlan) return;

    setLoading(plan);
    try {
      const res = await fetch('/api/stripe/checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ plan }),
      });

      const data = await res.json();
      if (data.url) {
        window.location.href = data.url;
      }
    } catch (err) {
      console.error('Checkout error:', err);
    } finally {
      setLoading(null);
    }
  }

  return (
    <div>
      <h2 className="text-2xl font-bold">Subscription</h2>
      <p className="text-gray-500 mt-2 mb-8">
        Choose the plan that fits your business needs.
      </p>

      {success && (
        <div className="mb-6 rounded-lg border border-green-200 bg-green-50 p-4 text-green-800">
          Your subscription has been activated successfully!
        </div>
      )}

      {cancelled && (
        <div className="mb-6 rounded-lg border border-yellow-200 bg-yellow-50 p-4 text-yellow-800">
          Checkout was cancelled. You can try again when you are ready.
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {plans.map((plan) => {
          const isCurrent = plan.id === currentPlan;
          const isUpgrade =
            plan.id !== 'free' &&
            plans.findIndex((p) => p.id === plan.id) >
              plans.findIndex((p) => p.id === currentPlan);

          return (
            <Card
              key={plan.id}
              className={
                isCurrent ? 'border-indigo-500 ring-2 ring-indigo-500' : ''
              }
            >
              <CardHeader>
                <div className="flex items-center justify-between">
                  <CardTitle className="text-lg">{plan.name}</CardTitle>
                  {isCurrent && <Badge variant="default">Current Plan</Badge>}
                </div>
                <CardDescription>{plan.description}</CardDescription>
              </CardHeader>
              <CardContent>
                <div className="mb-6">
                  <span className="text-4xl font-bold">{plan.price}EUR</span>
                  <span className="text-gray-500">{plan.period}</span>
                </div>
                <ul className="space-y-3">
                  {plan.features.map((feature) => (
                    <li key={feature} className="flex items-center gap-2">
                      <Check className="h-4 w-4 text-green-500 shrink-0" />
                      <span className="text-sm">{feature}</span>
                    </li>
                  ))}
                </ul>
              </CardContent>
              <CardFooter>
                {isCurrent ? (
                  <Button variant="outline" className="w-full" disabled>
                    Current Plan
                  </Button>
                ) : isUpgrade ? (
                  <Button
                    className="w-full"
                    onClick={() => handleUpgrade(plan.id)}
                    disabled={loading !== null}
                  >
                    {loading === plan.id ? 'Redirecting...' : 'Upgrade'}
                  </Button>
                ) : (
                  <Button variant="outline" className="w-full" disabled>
                    {plan.id === 'free' ? 'Free tier' : 'Downgrade'}
                  </Button>
                )}
              </CardFooter>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

